var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"MITCH_NPC_NULL_NULL","text":{"KOREA":"누, 눈으로 보고도 믿어지지 않는 전대미문의 시츄에이션─!","JPN":"ちょ、直接見ていても信じられない前代未聞のシチュエーション─！","ENG":"I-I can't believe the sight that's unfolding right in front of my eyes–!","TWN":"發，發生難以置信、前所未聞的情況—！"},"stage":{"bg":"CHARADE2_04","slots":{"L":null,"C":{"char_id":"MITCH_NPC_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"MITCH_NPC_NULL_NULL","text":{"KOREA":"함선 위에서나 볼 법한 공중전이 실제로 일어나고 있다구!!","JPN":"艦船の上でしか見られないような空中戦が目の前で起きてるよ！！","ENG":"We're actually witnessing an aerial battle that would normally happen on top of an aircraft!!","TWN":"只能在艦船上看到的空戰，現在竟然真實發生在眼前！！"},"stage":{"bg":"CHARADE2_04","slots":{"L":null,"C":{"char_id":"MITCH_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"MITCH_NPC_NULL_NULL","text":{"KOREA":"카나리아 스쿼드의 펠리세트가 전장의 스테이지를 뒤바꿔버렸다─!","JPN":"カナリア・スクワッドのフェリセットが戦場を変えた─！","ENG":"Canary Squad's Félicette completely changed the battlefield–!","TWN":"金絲雀小隊的費莉塞特扭轉了戰場上的局勢—！"},"stage":{"bg":"CHARADE2_04","slots":{"L":null,"C":{"char_id":"MITCH_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"MITCH_NPC_NULL_NULL","text":{"KOREA":"그야말로 뒤를 생각하지 않는, 카나리아 스쿼드 그 자체인 전략─!!","JPN":"当たって砕けろ的な、まさしくカナリア・スクワッドらしい戦略─！！","ENG":"It's a do-first-think-later tactic!! And it encompasses Canary Squad itself–!!","TWN":"這根本是不要命的戰術—！！"},"stage":{"bg":"CHARADE2_04","slots":{"L":null,"C":{"char_id":"MITCH_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"MITCH_NPC_NULL_NULL","text":{"KOREA":"천 미터 상공으로 치솟았던 챔피언과 챌린저! 체공시간이 끝나고 서서히 떨어지는데!","JPN":"1000メートル上空に飛びあがったチャンピオンとチャレンジャー！　滞空時間が終わり、少しずつ落下し始めているぞ！","ENG":"The champion and challenger soared over 1000 meters into the air! Their air time has ended, and they are slowly starting to fall!","TWN":"冠軍和挑戰者衝上幾百呎的高空後！現在正緩緩落下！"},"stage":{"bg":"CHARADE2_04","slots":{"L":null,"C":{"char_id":"MITCH_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"MITCH_NPC_NULL_NULL","text":{"KOREA":"설마! 설마! 정말로 해내는 거야? 카나리아 스쿼드?","JPN":"まさか！　まさか！　本当にやってしまうのか？　カナリア・スクワッド？","ENG":"No way! They can't! Can they?! Canary Squad?!","TWN":"難道！該不會！金絲雀小隊！成功了嗎？？"},"stage":{"bg":"CHARADE2_04","slots":{"L":null,"C":{"char_id":"MITCH_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"MITCH_NPC_NULL_NULL","text":{"KOREA":"아니, 그보다 죽으면 챔피언이든 뭐든 의미 없잖아─!!","JPN":"いや、それより死んでしまったらチャンピオンになっても意味がないよ─！！","ENG":"But if they die, there's no meaning in becoming the new champion–!!","TWN":"不過，要是因此死掉的話，那奪冠也沒什麼意義吧—！！"},"stage":{"bg":"CHARADE2_04","slots":{"L":null,"C":{"char_id":"MITCH_NPC_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"지금 제정신이야, 루이즈!?","JPN":"ルイーズ、何を考えているの！？","ENG":"Have you gone crazy, Louisé?!","TWN":"你有什麼毛病，露易絲？！"},"stage":{"bg":"CHARADE2_04","slots":{"L":null,"C":{"char_id":"MITCH_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"카운터인 나는 몰라도, 너희들은 여기서 떨어지면 틀림없이 죽는다고!","JPN":"カウンターである私はともかく、あなたたちはここから落ちたら確実に死ぬのよ！","ENG":"I'll be able to survive the fall because I'm a Counter. But you two will undoubtedly fall to your deaths!","TWN":"身為制裁者的我都不敢說，但你們從這裡掉下去是必死無疑的！"},"stage":{"bg":"CHARADE2_04","slots":{"L":null,"C":{"char_id":"MITCH_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"겨우 건틀렛에서 이기기 위해서 이런 짓까지 하는 거야?","JPN":"ガントレットなんかで勝つためにここまでやる？","ENG":"You're risking your lives just to win the Gauntlet?!","TWN":"就只是想要在聖鎧中獲勝，有需要做到這樣嗎？"},"stage":{"bg":"CHARADE2_04","slots":{"L":null,"C":{"char_id":"MITCH_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"대체 왜!?","JPN":"いったいどうして！？","ENG":"Just why?!","TWN":"到底為什麼？！"},"stage":{"bg":"CHARADE2_04","slots":{"L":null,"C":{"char_id":"MITCH_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"말했잖아요! 이게 내 복수라고!","JPN":"言ったはずです！　これが私の復讐だって！","ENG":"I told you! This is my revenge!","TWN":"我說過！這就是我的報仇！"},"stage":{"bg":"CHARADE2_04","slots":{"L":null,"C":{"char_id":"MITCH_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"처음부터 당신의 목숨 따위 빼앗아 봐야 의미 없는 거였어!","JPN":"最初からあなたの命なんか奪っても意味なかったのよ！","ENG":"It was meaningless to take your life from the start!","TWN":"打從一開始就是如此，就算奪走你的性命也沒什麼意義！"},"stage":{"bg":"CHARADE2_04","slots":{"L":null,"C":{"char_id":"MITCH_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"모두가 도와 줬는데, 당신 목숨 따위로 더럽혀선 안 되는 거였어!","JPN":"みんなに助けられたのに、あなたの命なんかで手を汚しちゃいけなかったのよ！","ENG":"Everyone helped me, so it shouldn't be tainted by killing you!","TWN":"大家都在幫我，我不能用你的性命來辜負他們的心意！"},"stage":{"bg":"CHARADE2_04","slots":{"L":null,"C":{"char_id":"MITCH_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"그러니까 승리를……! 당신에게서 챔피언 타이틀을 빼앗는 거야!","JPN":"だから、勝利を……！　あなたからチャンピオンのタイトルを奪うの！","ENG":"So my revenge...! Is to take away your title as champion!","TWN":"所以我要把勝利……！把冠軍這個頭銜從你身上搶走！"},"stage":{"bg":"CHARADE2_04","slots":{"L":null,"C":{"char_id":"MITCH_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};